const body = $input.first().json.body || $input.first().json;
const question = (body.question || '').trim();
if (!question) throw new Error('No question provided');

const q = question.toLowerCase();

const negationWords = [
  "don't", "dont", "do not", "doesn't", "doesnt", "does not",
  "never", "without", "skip", "avoid", "stop", "cancel",
  "no need for", "no need to", "not", "no"
];

const reportWords = [
  "report", "summary", "overview", "breakdown",
  "weekly", "monthly", "last week", "past week",
  "7 days", "one week",
  "last month", "past month",
  "30 days", "one month"
];

const esc = s => s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
const negPattern = negationWords.map(esc).join('|');
const trigPattern = reportWords.map(esc).join('|');

// Does the question contain any report-style trigger word at all?
const trigRegex = new RegExp(`\\b(${trigPattern})\\b`, 'i');
const wantsReport = trigRegex.test(q);

// Negation near a trigger word, in either direction
const negBefore = new RegExp(`\\b(${negPattern})\\b(\\s+\\S+){0,5}\\s*\\b(${trigPattern})\\b`, 'i');
const negAfter = new RegExp(`\\b(${trigPattern})\\b(\\s+\\S+){0,4}\\s*\\b(${negPattern})\\b`, 'i');
const negated = negBefore.test(q) || negAfter.test(q);

// Final decision: only a report if it explicitly wants one AND isn't negated
const is_report = wantsReport && !negated;

// Day-range extraction (only meaningful for reports)
let days = null;
const match = q.match(/(\d+)\s*(day|days)/i);
if (match) {
  days = parseInt(match[1], 10);
}
if (!days) {
  if (q.includes('week')) days = 7;
  else if (q.includes('month')) days = 30;
  else if (q.includes('today')) days = 1;
  else if (q.includes('tomorrow')) days = 2;
}
if (!days) days = 10;

let report_type = null;
if (is_report) {
  report_type = q.includes('expir') ? 'expiry_report' : 'general_report';
}

let date_context = '';
if (report_type === 'expiry_report') {
  date_context = `expiry_date <= CURRENT_DATE + INTERVAL '${days} day'`;
}

return [{
  json: {
    question,
    report_type,
    days,
    is_report,
    negated,
    date_context,
    timestamp: new Date().toISOString()
  }
}];

