const groqResponse = $input.first().json;
const raw = groqResponse.choices?.[0]?.message?.content || '';
let sql = raw.replace(/```sql/gi, '').replace(/```/g, '').trim();

// Block destructive statements
const forbidden = /\b(DROP|DELETE|UPDATE|INSERT|ALTER|TRUNCATE|CREATE|GRANT|REVOKE)\b/i;
if (forbidden.test(sql)) {
  throw new Error('Blocked: destructive SQL detected');
}

if (!sql.toLowerCase().startsWith('select')) {
  throw new Error('Only SELECT queries are allowed. Got: ' + sql.substring(0, 80));
}

const parseNode = $('Parse & Classify Input').first().json;

return [{
  json: {
    sql,
    question: parseNode.question,
    is_report: false,
    timestamp: parseNode.timestamp
  }
}];

const rows = $input.all().map(i => i.json);
const meta = $('Clean Report SQL').first().json;

const now = new Date();
const dateStr = now.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
const timeStr = now.toLocaleTimeString('en-US');

let content = '';

content += '         PHARMACY DATABASE REPORT          \n';

content += `Date       : ${dateStr}\n`;
content += `Time       : ${timeStr}\n`;
content += `Question   : ${meta.question}\n`;
content += `Report Type: ${meta.report_type || 'general'}\n`;
content += `Total Rows : ${rows.length}\n`;


if (rows.length === 0) {
  content += 'No data found for this report period.\n';
} else {
  const cols = Object.keys(rows[0]);

  // Column widths
  const widths = {};
  cols.forEach(c => {
    widths[c] = c.length;
    rows.forEach(r => {
      const val = r[c] === null || r[c] === undefined ? 'N/A' : String(r[c]);
      if (val.length > widths[c]) widths[c] = val.length;
    });
  });

  // Header row
  const headerLine = cols.map(c => c.toUpperCase().padEnd(widths[c])).join('  |  ');
  const dividerLine = cols.map(c => '-'.repeat(widths[c])).join('--+--');
  content += headerLine + '\n';
  content += dividerLine + '\n';

  // Data rows
  rows.slice(0, 500).forEach((r, i) => {
    const line = cols.map(c => {
      let val = r[c];
      if (val === null || val === undefined) return 'N/A'.padEnd(widths[c]);
      if (typeof val === 'string' && val.match(/^\d{4}-/)) {
        val = new Date(val).toLocaleDateString('en-US', { year: 'numeric', month: 'short', day: 'numeric' });
      }
      return String(val).padEnd(widths[c]);
    }).join('  |  ');
    content += line + '\n';
  });

  if (rows.length > 500) {
    content += `\n... ${rows.length - 500} more rows not shown.\n`;
  }
}


content += '              END OF REPORT               \n';


const filename = `pharmacy_report_${meta.report_type || 'general'}_${Date.now()}.txt`;

return [{
  json: {
    success: true,
    type: 'report',
    report_type: meta.report_type,
    question: meta.question,
    filename,
    content,
    row_count: rows.length,
    sql_used: meta.sql,
    timestamp: meta.timestamp
  }
}];

const rows = $input.all().map(i => i.json);
const meta = $('Clean QA SQL').first().json;

if (!rows || rows.length === 0) {
  return [{
    json: {
      success: true,
      type: 'qa',
      question: meta.question,
      answer: 'No results found for your question.',
      row_count: 0,
      rows: [],
      sql_used: meta.sql,
      timestamp: meta.timestamp
    }
  }];
}

// Single value answer (e.g. COUNT)
if (rows.length === 1 && Object.keys(rows[0]).length === 1) {
  const key = Object.keys(rows[0])[0];
  const val = rows[0][key];
  return [{
    json: {
      success: true,
      type: 'qa',
      question: meta.question,
      answer: `**${key}:** ${val}`,
      row_count: 1,
      rows: rows,
      sql_used: meta.sql,
      timestamp: meta.timestamp
    }
  }];
}

const cols = Object.keys(rows[0]);
const header = cols.join(' | ');
const divider = cols.map(() => '---').join(' | ');
const dataRows = rows.slice(0, 50).map(r =>
  cols.map(c => {
    const val = r[c];
    if (val === null || val === undefined) return 'N/A';
    if (val instanceof Date || (typeof val === 'string' && val.match(/^\d{4}-/))) {
      return new Date(val).toLocaleDateString('en-US', { year: 'numeric', month: 'short', day: 'numeric' });
    }
    return String(val);
  }).join(' | ')
);

const table = [header, divider, ...dataRows].join('\n');
const note = rows.length > 50 ? `\n\n> Showing 50 of ${rows.length} total rows.` : '';

return [{
  json: {
    success: true,
    type: 'qa',
    question: meta.question,
    answer: table + note,
    row_count: rows.length,
    rows: rows,
    sql_used: meta.sql,
    timestamp: meta.timestamp
  }
}];

const rows = $json.rows;
const question = $json.question;

if (!rows || rows.length === 0) {
  return [{ json: { ...$json, answer: "No data found." } }];
}

// COUNT case
if (rows.length === 1 && Object.keys(rows[0]).length === 1) {
  const key = Object.keys(rows[0])[0];
  const value = rows[0][key];

  return [{
    json: {
      ...$json,
      answer: `There are ${value} records in the database.`
    }
  }];
}

// default table summary
return [{
  json: {
    ...$json,
    answer: `Found ${rows.length} records matching your query.`
  }
}];

const data = $input.first().json;

// Convert text content to base64
const base64 = Buffer.from(data.content, 'utf8').toString('base64');

return [{
  json: { ...data },
  binary: {
    report: {
      data: base64,
      mimeType: 'text/plain',
      fileName: data.filename,
      fileExtension: 'txt'
    }
  }
}];

const sql = $input.first().json.sql;

if (!sql || typeof sql !== 'string' || sql.trim().length === 0) {
  throw new Error('No SQL received from query enforcer');
}

// Block destructive statements
const forbidden = /\b(DROP|DELETE|UPDATE|INSERT|ALTER|TRUNCATE|CREATE|GRANT|REVOKE)\b/i;
if (forbidden.test(sql)) {
  throw new Error('Blocked: destructive SQL detected');
}

if (!sql.toLowerCase().trim().startsWith('select')) {
  throw new Error('Only SELECT queries are allowed. Got: ' + sql.substring(0, 80));
}

const parseNode = $('Parse & Classify Input').first().json;

return [{
  json: {
    sql,
    question: parseNode.question,
    report_type: parseNode.report_type,
    is_report: true,
    timestamp: parseNode.timestamp
  }
}];

const item = $input.first().json;

let sql =
  item.choices?.[0]?.message?.content ||
  item.message?.content ||
  item.text ||
  item.sql ||
  '';

if (!sql || typeof sql !== 'string' || sql.trim().length === 0) {
  throw new Error('Groq returned empty SQL. Check model response.');
}

// cleanup
sql = sql.replace(/```sql/gi, '').replace(/```/g, '').trim();
sql = sql.replace(/;+$/g, '');
sql = sql.replace(/limit\s+\d+/i, '');

if (!sql.toLowerCase().startsWith('select')) {
  throw new Error('Only SELECT queries are allowed. Got: ' + sql.substring(0, 100));
}

const { question, days } = $('Parse & Classify Input').first().json;
const q = question.toLowerCase();

// Only force a date-range filter for genuinely expiry-related questions
const isExpiryQuestion = q.includes('expir');

if (isExpiryQuestion) {
  const condition = `expiry_date BETWEEN CURRENT_DATE AND (CURRENT_DATE + INTERVAL '${days || 10} day')`;

  if (sql.toLowerCase().includes('where')) {
    if (!sql.toLowerCase().includes('expiry_date')) {
      sql = sql.replace(/where/i, `WHERE ${condition} AND`);
    }
  } else {
    sql += ` WHERE ${condition}`;
  }
}

sql += ' LIMIT 500';

return [{ json: { sql } }];
